messages.content:
This is a missed-optimization in GVN.

The following program reveals the missed optimization.
The source program is
```llvm
define i1 @not_cond_logic1(i1 %c, i1 %d) {
  %c.not = xor i1 %c, true
  %and = and i1 %c.not, %d
  br i1 %and, label %if, label %else

if:                                               ; preds = %0
  ret i1 %c

else:                                             ; preds = %0
  ret i1 %c
}

```

However, current LLVM cannot optimize the source program. The expected optimized program is
```llvm
define i1 @not_cond_logic1(i1 %c, i1 %d) {
  %c.not = xor i1 %c, true
  %and = and i1 %c.not, %d
  br i1 %and, label %if, label %else

if:                                               ; preds = %0
  ret i1 false

else:                                             ; preds = %0
  ret i1 %c
}

```
Please modify the following code in llvm/lib/Transforms/Scalar/GVN.cpp:GVNPass::propagateEquality to implement the missed optimization:
```cpp
      if (RootDominatesEnd)
        LeaderTable.insert(Num, NotVal, Root.getEnd());

      continue;
    }

    // Propagate equalities that results from truncation with no unsigned wrap
    // like (trunc nuw i64 %v to i1) == "true" or (trunc nuw i64 %v to i1) ==
    // "false"
    if (match(LHS, m_NUWTrunc(m_Value(A)))) {
      Worklist.emplace_back(A, ConstantInt::get(A->getType(), IsKnownTrue));
      continue;
    }
  }

  return Changed;
}

/// When calculating availability, handle an instruction
/// by inserting it into the appropriate sets.
bool GVNPass::processInstruction(Instruction *I) {
  // If the instruction can be easily simplified then do so now in preference
